import { useState, useEffect, useRef, useCallback } from "react";

const HAMSTER = "data:image/jpeg;base64,";
const BG      = "data:image/png;base64,";

const STAGES = [
  { id:0, label:"Bien",    bg:"#2196F3", border:"#0d47a1", fade:"rgba(255,255,255,0.52)" },
  { id:1, label:"Vale",    bg:"#4CAF50", border:"#1b5e20", fade:"rgba(255,255,255,0.48)" },
  { id:2, label:"Meh",     bg:"#FDD835", border:"#f9a825", fade:"rgba(100,60,0,0.40)"   },
  { id:3, label:"Cuidado", bg:"#FF7043", border:"#bf360c", fade:"rgba(255,255,255,0.48)" },
  { id:4, label:"EVIL \ud83d\udc79", bg:"#D32F2F", border:"#7f0000", fade:"rgba(255,255,255,0.48)" },
];
const COLORS = ["#e74c3c","#e67e22","#f1c40f","#27ae60","#1abc9c","#2980b9","#8e44ad","#e91e63","#d35400","#6c5ce7"];
const rnd = () => COLORS[Math.floor(Math.random()*COLORS.length)];
function dk(hex){
  try{
    let c=hex.replace("#","");
    if(c.length===3)c=c.split("").map(x=>x+x).join("");
    const n=parseInt(c,16);
    const r=Math.max(0,(n>>16)-60),g=Math.max(0,((n>>8)&255)-60),b=Math.max(0,(n&255)-60);
    return "#"+[r,g,b].map(v=>v.toString(16).padStart(2,"0")).join("");
  }catch{return "#333";}
}

/* ── Alarm sound (Web Audio API) ── */
function playAlarm(ctx) {
  if (!ctx) return;
  const notes = [523,659,784,1047,784,1047,784];
  notes.forEach((freq, i) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain); gain.connect(ctx.destination);
    osc.type = "sine";
    osc.frequency.setValueAtTime(freq, ctx.currentTime + i*0.18);
    gain.gain.setValueAtTime(0.35, ctx.currentTime + i*0.18);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i*0.18 + 0.16);
    osc.start(ctx.currentTime + i*0.18);
    osc.stop(ctx.currentTime + i*0.18 + 0.18);
  });
}

/* ── Clip Left ── */
function ClipL({ clip, onDragStart, top }) {
  const [hov,setHov]=useState(false);
  const [jig,setJig]=useState(false);
  const c=clip.color, d=dk(c);
  return (
    <div draggable onDragStart={e=>onDragStart(e,clip.id)}
      onClick={()=>{setJig(true);setTimeout(()=>setJig(false),380);}}
      onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}
      style={{position:"absolute",right:"100%",top,marginRight:-5,
        transform:jig?"rotate(-18deg)":hov?"rotate(-10deg)":"rotate(-6deg)",
        transformOrigin:"right center",transition:"transform 0.18s cubic-bezier(.34,1.56,.64,1)",
        filter:hov?`drop-shadow(0 3px 10px ${c}bb)`:"drop-shadow(0 2px 5px rgba(0,0,0,0.3))",
        cursor:"grab",userSelect:"none",zIndex:hov?30:10,display:"flex",alignItems:"center"}}>
      <div style={{position:"relative",minWidth:90,maxWidth:180,height:36,background:c,
        borderRadius:"8px 5px 5px 8px",border:`2.5px solid ${d}`,display:"flex",
        alignItems:"center",justifyContent:"center",padding:"0 14px 0 10px",
        boxShadow:"inset 0 2px 5px rgba(255,255,255,0.22),inset 0 -2px 4px rgba(0,0,0,0.18)"}}>
        <div style={{background:"white",borderRadius:5,padding:"2px 8px",border:`1.5px solid ${d}`,
          fontSize:13,fontFamily:"'Fredoka One',cursive",fontWeight:"bold",color:d,
          whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",maxWidth:150,lineHeight:1.5}}>
          {clip.name}
        </div>
        <div style={{position:"absolute",right:-7,top:"50%",transform:"translateY(-50%)",
          width:9,height:9,borderRadius:"50%",background:d,border:"2px solid rgba(255,255,255,0.5)"}}/>
      </div>
    </div>
  );
}

