/* ── Stage Row ── */
function Row({ stage, clips, onDrop, onDragStart, isBottom }) {
  const [glow,setGlow]=useState(false);
  const L=clips.filter((_,i)=>i%2===0), R=clips.filter((_,i)=>i%2===1);
  const minH=Math.max(72,Math.max(L.length,R.length)*52+20);
  return (
    <div onDragOver={e=>{e.preventDefault();setGlow(true);}} onDragLeave={()=>setGlow(false)}
      onDrop={e=>{setGlow(false);onDrop(e,stage.id);}}
      style={{position:"relative",minHeight:minH,background:stage.bg,
        borderLeft:`5px solid ${stage.border}`,borderRight:`5px solid ${stage.border}`,
        borderBottom:isBottom?`5px solid ${stage.border}`:`2px solid ${stage.border}99`,
        borderRadius:isBottom?"0 0 16px 16px":"0",
        boxShadow:glow?"inset 0 0 0 5px rgba(255,255,255,0.55)":"none",
        transition:"box-shadow 0.15s",overflow:"visible",
        display:"flex",alignItems:"center",justifyContent:"center"}}>
      {L.map((c,i)=><ClipL key={c.id} clip={c} onDragStart={onDragStart} top={10+i*52}/>)}
      <div style={{fontFamily:"'Fredoka One',cursive",fontSize:30,color:stage.fade,
        letterSpacing:1.2,userSelect:"none",padding:"10px 120px"}}>{stage.label}</div>
      {R.map((c,i)=><ClipR key={c.id} clip={c} onDragStart={onDragStart} top={10+i*52}/>)}
    </div>
  );
}

/* ── Hamster Bracket ── */
