/* ── Timer ── */
function Timer() {
  const [inputVal, setInputVal] = useState("5:00");
  const [totalSecs, setTotalSecs] = useState(300);
  const [secsLeft, setSecsLeft]   = useState(null);
  const [running, setRunning]     = useState(false);
  const [done, setDone]           = useState(false);
  const intervalRef = useRef(null);
  const audioCtxRef = useRef(null);

  function getAudioCtx() {
    if (!audioCtxRef.current) {
      try { audioCtxRef.current = new (window.AudioContext || window.webkitAudioContext)(); } catch(e){}
    }
    return audioCtxRef.current;
  }

  function playAlarmSound() {
    const ctx = getAudioCtx();
    if (!ctx) return;
    // Cute 7-note chime: C E G C' G C' G
    const melody = [523,659,784,1047,784,1047,784];
    melody.forEach((freq,i) => {
      const osc  = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = "sine";
      osc.frequency.setValueAtTime(freq, ctx.currentTime + i*0.19);
      gain.gain.setValueAtTime(0.38, ctx.currentTime + i*0.19);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i*0.19 + 0.17);
      osc.start(ctx.currentTime + i*0.19);
      osc.stop(ctx.currentTime  + i*0.19 + 0.20);
    });
  }

  // Parse "M:SS" or plain number input
  function parseInput(val) {
    const trimmed = val.trim();
    if (trimmed.includes(":")) {
      const [m, s] = trimmed.split(":").map(Number);
      if (!isNaN(m) && !isNaN(s)) return Math.max(1, m*60 + (s||0));
    }
    const n = parseInt(trimmed);
    if (!isNaN(n) && n > 0) return n * 60;
    return null;
  }

  function handleInputChange(e) {
    setInputVal(e.target.value);
  }

  function handleInputBlur() {
    const secs = parseInput(inputVal);
    if (secs) {
      setTotalSecs(secs);
      const m = Math.floor(secs/60), s = secs%60;
      setInputVal(`${m}:${String(s).padStart(2,"0")}`);
    } else {
      const m = Math.floor(totalSecs/60), s = totalSecs%60;
      setInputVal(`${m}:${String(s).padStart(2,"0")}`);
    }
  }

  useEffect(() => {
    if (running && secsLeft > 0) {
      intervalRef.current = setInterval(() => {
        setSecsLeft(s => {
          if (s <= 1) {
            clearInterval(intervalRef.current);
            setRunning(false);
            setDone(true);
            setTimeout(playAlarmSound, 50);
            return 0;
          }
          return s - 1;
        });
      }, 1000);
    }
    return () => clearInterval(intervalRef.current);
  }, [running]);

  function start() {
    getAudioCtx(); // unlock audio on user gesture
    const secs = parseInput(inputVal);
    const t = secs || totalSecs;
    setTotalSecs(t);
    setSecsLeft(t);
    setDone(false);
    setRunning(true);
  }

  function stop() {
    clearInterval(intervalRef.current);
    setRunning(false);
    setSecsLeft(null);
    setDone(false);
  }

  const display = secsLeft !== null
    ? `${String(Math.floor(secsLeft/60)).padStart(2,"0")}:${String(secsLeft%60).padStart(2,"0")}`
    : inputVal;

  const pct = secsLeft !== null ? (secsLeft/totalSecs)*100 : 100;
  const color = done ? "#D32F2F" : secsLeft===null ? "#27ae60" : pct>50 ? "#27ae60" : pct>25 ? "#f39c12" : "#e74c3c";

  return (
    <div style={{background:"white",borderRadius:18,padding:"16px 18px",
      boxShadow:"0 8px 28px rgba(0,0,0,0.18)",display:"flex",flexDirection:"column",
      alignItems:"center",gap:10,width:170,border:"3px solid #e0e0e0"}}>

      {/* Hamster — normal bouncing or big RED when done */}
      <div style={{position:"relative",width:90,height:90,display:"flex",alignItems:"center",justifyContent:"center"}}>
        <img src={HAMSTER} alt="timer hamster"
          style={{
            width:done?110:90, height:"auto", display:"block",
            transition:"width 0.3s, filter 0.3s",
            filter: done
              ? "hue-rotate(300deg) saturate(2) brightness(1.1) drop-shadow(0 0 8px #ff000088)"
              : "none",
            animation: done
              ? "hamShake 0.35s ease-in-out infinite"
              : running ? "hamBounce 2s ease-in-out infinite" : "none",
          }}
          onError={e=>{e.target.style.display="none";}}/>
        {done && (
          <div style={{position:"absolute",top:-18,left:"50%",transform:"translateX(-50%)",
            fontSize:28,animation:"hamShake 0.4s ease-in-out infinite"}}>🚨</div>
        )}
      </div>

      {/* Time display / input */}
      {!running ? (
        <input
          value={display}
          onChange={handleInputChange}
          onBlur={handleInputBlur}
          onKeyDown={e=>e.key==="Enter"&&handleInputBlur()}
          style={{fontFamily:"'Fredoka One',cursive",fontSize:34,color,lineHeight:1,
            textAlign:"center",border:"none",borderBottom:`3px solid ${color}`,
            outline:"none",width:"100%",background:"transparent",letterSpacing:2,
            transition:"color 0.5s, border-color 0.5s"}}
        />
      ) : (
        <div style={{fontFamily:"'Fredoka One',cursive",fontSize:34,color,lineHeight:1,
          textShadow:`0 2px 8px ${color}44`,letterSpacing:2,transition:"color 0.5s"}}>
          {display}
        </div>
      )}

      {/* Hint */}
      {!running && !done && (
        <div style={{fontSize:10,color:"#aaa",fontFamily:"'Fredoka One',cursive",textAlign:"center",marginTop:-6}}>
          Escribe M:SS o minutos
        </div>
      )}

      {/* Progress bar */}
      {secsLeft !== null && (
        <div style={{width:"100%",height:8,background:"#eee",borderRadius:4,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${pct}%`,background:color,borderRadius:4,
            transition:"width 1s linear,background 0.5s"}}/>
        </div>
      )}

      {done && (
        <div style={{fontFamily:"'Fredoka One',cursive",fontSize:14,color:"#D32F2F",
          textAlign:"center",fontWeight:"bold"}}>¡Tiempo! 🛑</div>
      )}

      {/* Buttons */}
      <div style={{display:"flex",gap:8,width:"100%",justifyContent:"center"}}>
        {!running && !done && (
          <button onClick={start}
            style={{flex:1,background:"linear-gradient(135deg,#1DD1A1,#0abf7a)",color:"#fff",
              border:"none",borderRadius:10,padding:"8px 0",fontFamily:"'Fredoka One',cursive",
              fontSize:14,cursor:"pointer",boxShadow:"0 3px 10px rgba(29,209,161,0.4)"}}>
            ▶ Start
          </button>
        )}
        {running && (
          <button onClick={stop}
            style={{flex:1,background:"linear-gradient(135deg,#e74c3c,#c0392b)",color:"#fff",
              border:"none",borderRadius:10,padding:"8px 0",fontFamily:"'Fredoka One',cursive",
              fontSize:14,cursor:"pointer",boxShadow:"0 3px 10px rgba(231,76,60,0.4)"}}>
            ⏹ Stop
          </button>
        )}
        {done && (
          <button onClick={stop}
            style={{flex:1,background:"linear-gradient(135deg,#54A0FF,#2e86de)",color:"#fff",
              border:"none",borderRadius:10,padding:"8px 0",fontFamily:"'Fredoka One',cursive",
              fontSize:14,cursor:"pointer",boxShadow:"0 3px 10px rgba(84,160,255,0.4)"}}>
            🔄 Reset
          </button>
        )}
      </div>
    </div>
  );
}

/* ── Edit Modal ── */
function EditModal({ clips, onSave, onClose }) {
  const [ec,setEc]=useState(clips.map(c=>({...c})));
  const [name,setName]=useState("");
  const upd=(id,f,v)=>setEc(p=>p.map(c=>c.id===id?{...c,[f]:v}:c));
  const add=()=>{if(!name.trim())return;setEc(p=>[...p,{id:Date.now(),name:name.trim(),color:rnd(),stage:1}]);setName("");};
  return (
    <div style={{position:"fixed",inset:0,zIndex:100,background:"rgba(10,10,40,0.78)",
      backdropFilter:"blur(6px)",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{background:"#fffbe8",borderRadius:22,boxShadow:"0 24px 80px rgba(0,0,0,0.35)",
        padding:"26px 30px",width:"min(95vw,490px)",maxHeight:"88vh",overflowY:"auto",
        fontFamily:"'Fredoka One',cursive",position:"relative"}}>
        <button onClick={onClose} style={{position:"absolute",top:13,right:15,background:"#e74c3c",
          color:"#fff",border:"none",borderRadius:"50%",width:30,height:30,fontSize:16,cursor:"pointer",fontWeight:900}}>✕</button>
        <h2 style={{color:"#7a4500",fontSize:22,textAlign:"center",margin:"0 0 14px"}}>✏️ Editar Fichas</h2>
        <div style={{display:"flex",gap:8,marginBottom:18}}>
          <input value={name} onChange={e=>setName(e.target.value)} onKeyDown={e=>e.key==="Enter"&&add()}
            placeholder="Nombre del estudiante…"
            style={{flex:1,padding:"8px 12px",borderRadius:10,border:"2px solid #ffd080",
              fontFamily:"'Fredoka One',cursive",fontSize:13,outline:"none"}}/>
          <button onClick={add} style={{background:"#3498db",color:"#fff",border:"none",borderRadius:10,
            padding:"8px 14px",fontFamily:"'Fredoka One',cursive",fontSize:13,cursor:"pointer"}}>+ Añadir</button>
        </div>
        {ec.map(clip=>(
          <div key={clip.id} style={{display:"flex",alignItems:"center",gap:8,background:"#fff",
            borderRadius:11,padding:"8px 11px",marginBottom:8,border:`2px solid ${clip.color}88`}}>
            <div style={{width:30,height:30,borderRadius:"50%",background:clip.color,
              border:`2px solid ${dk(clip.color)}`,flexShrink:0}}/>
            <input value={clip.name} onChange={e=>upd(clip.id,"name",e.target.value)}
              style={{flex:1,border:"none",background:"transparent",fontFamily:"'Fredoka One',cursive",
                fontSize:14,color:"#333",outline:"none"}}/>
            <input type="color" value={clip.color} onChange={e=>upd(clip.id,"color",e.target.value)}
              style={{width:26,height:26,border:"none",borderRadius:6,cursor:"pointer",padding:0}}/>
            <button onClick={()=>upd(clip.id,"color",rnd())} style={{background:"#f39c12",border:"none",
              borderRadius:6,padding:"4px 7px",fontSize:12,cursor:"pointer"}}>🎲</button>
            <button onClick={()=>setEc(p=>p.filter(c=>c.id!==clip.id))} style={{background:"#e74c3c",
              color:"#fff",border:"none",borderRadius:6,padding:"4px 8px",fontSize:11,cursor:"pointer",fontWeight:700}}>✕</button>
          </div>
        ))}
        <div style={{display:"flex",justifyContent:"center",marginTop:16}}>
          <button onClick={()=>onSave(ec)} style={{background:"#1abc9c",color:"#fff",border:"none",
            borderRadius:12,padding:"10px 34px",fontFamily:"'Fredoka One',cursive",fontSize:16,cursor:"pointer"}}>
            💾 Guardar
          </button>
        </div>
      </div>
    </div>
  );
}

function Confetti() {
  const cols=["#FFD700","#FF6B6B","#54A0FF","#1DD1A1","#FF9FF3","#FECA57","#e67e22"];
  return (
    <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:200}}>
      {Array.from({length:24},(_,i)=>(
        <div key={i} style={{position:"absolute",top:"-8%",left:`${(i*4.2)%100}%`,width:10,height:10,
          borderRadius:i%2===0?"50%":2,background:cols[i%cols.length],
          animation:`cFall ${1.3+(i%4)*0.5}s ${i*0.065}s linear infinite`}}/>
      ))}
    </div>
  );
}

const INIT = [
  {id:1,name:"Alex",   color:"#e74c3c",stage:1},
  {id:2,name:"Jamie",  color:"#2980b9",stage:1},
  {id:3,name:"Sam",    color:"#f39c12",stage:1},
  {id:4,name:"Jordan", color:"#27ae60",stage:1},
  {id:5,name:"Riley",  color:"#8e44ad",stage:1},
  {id:6,name:"Casey",  color:"#e91e63",stage:1},
];

export default function App() {
  const [clips,setClips]       = useState(INIT);
  const [dragId,setDragId]     = useState(null);
  const [showEdit,setShowEdit] = useState(false);
  const [confetti,setConfetti] = useState(false);
  const [toast,setToast]       = useState(null);

  const absent  = clips.filter(c=>c.stage==="absent");
  const byStage = id=>clips.filter(c=>c.stage===id);
  const hamster = clips.filter(c=>c.stage===99);

  function onDragStart(e,id){setDragId(id);e.dataTransfer.effectAllowed="move";}
  function onDrop(e,target){
    e.preventDefault();if(dragId==null)return;
    const clip=clips.find(c=>c.id===dragId);if(!clip)return;
    setClips(p=>p.map(c=>c.id===dragId?{...c,stage:target}:c));
    setDragId(null);
    if(target===99){setConfetti(true);setTimeout(()=>setConfetti(false),2500);pop(`⭐ ${clip.name} — ¡Extra Punto!`);}
    else if(target==="absent")pop(`😢 ${clip.name} está ausente`);
    else if(target===4)pop(`😈 ${clip.name} — ¡sin puntos diarios!`);
    else if(typeof clip.stage==="number"&&target<clip.stage)pop(`⬆️ ${clip.name} subió`);
    else if(typeof clip.stage==="number"&&target>clip.stage)pop(`⬇️ ${clip.name} bajó...`);
  }
  function pop(msg){setToast(msg);setTimeout(()=>setToast(null),2700);}
  function save(nc){setClips(nc.map(c=>({...c,stage:c.stage??1})));setShowEdit(false);pop("✅ ¡Guardado!");}

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fredoka+One&display=swap');
        *{box-sizing:border-box}body{margin:0;padding:0}
        @keyframes titleBounce{0%,100%{transform:translateY(0)}50%{transform:translateY(-5px)}}
        @keyframes cFall{0%{transform:translateY(-40px) rotate(0);opacity:1}100%{transform:translateY(110vh) rotate(540deg);opacity:0}}
        @keyframes tIn{0%{transform:translateX(-50%) translateY(18px);opacity:0}100%{transform:translateX(-50%) translateY(0);opacity:1}}
        @keyframes hamBounce{0%,100%{transform:translateY(0) rotate(-2deg)}50%{transform:translateY(-7px) rotate(2deg)}}
        @keyframes hamShake{0%,100%{transform:rotate(-6deg) scale(1.05)}50%{transform:rotate(6deg) scale(1.05)}}
        @keyframes starPulse{0%,100%{transform:scale(1)}50%{transform:scale(1.18)}}
        @keyframes alarmPulse{0%,100%{box-shadow:0 8px 28px rgba(0,0,0,0.18)}50%{box-shadow:0 0 0 6px rgba(211,47,47,0.4),0 8px 28px rgba(0,0,0,0.18)}}
      `}</style>

      <div style={{
        minHeight:"100vh",
        backgroundImage:`url(data:image/png;base64,${BG})`,
        backgroundSize:"cover",backgroundPosition:"center",backgroundAttachment:"fixed",
        padding:"28px 14px 60px",position:"relative",overflowX:"hidden",fontFamily:"'Fredoka One',cursive",
      }}>
        {confetti&&<Confetti/>}
        {toast&&(
          <div style={{position:"fixed",bottom:22,left:"50%",background:"rgba(15,10,50,0.93)",
            color:"#fff",borderRadius:16,padding:"10px 24px",fontFamily:"'Fredoka One',cursive",
            fontSize:14,zIndex:300,boxShadow:"0 8px 28px rgba(0,0,0,0.3)",
            animation:"tIn .24s ease",backdropFilter:"blur(8px)",whiteSpace:"nowrap"}}>{toast}</div>
        )}

        {/* Header */}
        <div style={{textAlign:"center",marginBottom:28,position:"relative",zIndex:2}}>
          <h1 style={{fontFamily:"'Fredoka One',cursive",fontSize:"clamp(26px,5vw,44px)",color:"#fff",
            textShadow:"0 3px 12px rgba(0,0,0,0.35)",margin:0,
            display:"inline-flex",alignItems:"center",gap:14,
            animation:"titleBounce 2.8s ease-in-out infinite",letterSpacing:1}}>
            <span style={{display:"flex",gap:3,animation:"starPulse 2s ease-in-out infinite"}}>
              <span style={{fontSize:"0.65em"}}>⭐</span>
              <span style={{fontSize:"0.9em"}}>⭐</span>
              <span style={{fontSize:"0.65em"}}>⭐</span>
            </span>
            🎓 Tabla de Comportamiento
            <span style={{display:"flex",gap:3,animation:"starPulse 2s ease-in-out infinite 0.3s"}}>
              <span style={{fontSize:"0.65em"}}>⭐</span>
              <span style={{fontSize:"0.9em"}}>⭐</span>
              <span style={{fontSize:"0.65em"}}>⭐</span>
            </span>
          </h1>
          <p style={{color:"rgba(255,255,255,0.85)",fontSize:13,marginTop:6,
            fontFamily:"'Fredoka One',cursive",textShadow:"0 1px 4px rgba(0,0,0,0.3)"}}>
            Arrastra fichas entre niveles • Suelta en la papelera para ausencias
          </p>
        </div>

        {/* Main layout */}
        <div style={{display:"flex",gap:32,justifyContent:"center",alignItems:"flex-start",
          position:"relative",zIndex:2,paddingLeft:120,paddingRight:120,maxWidth:1000,margin:"0 auto"}}>

          {/* Chart */}
          <div style={{flex:"0 0 auto",width:"min(76vw,560px)",borderRadius:20,
            boxShadow:"0 12px 50px rgba(0,0,0,0.28)",border:"4px solid rgba(255,255,255,0.7)",
            overflow:"visible",position:"relative"}}>
            <HamsterBracket clips={hamster} onDrop={onDrop} onDragStart={onDragStart}/>
            <div style={{borderRadius:"0 0 16px 16px",overflow:"visible"}}>
              {STAGES.map((s,i)=>(
                <Row key={s.id} stage={s} clips={byStage(s.id)} onDrop={onDrop}
                  onDragStart={onDragStart} isBottom={i===STAGES.length-1}/>
              ))}
            </div>
          </div>

          {/* Right panel — NO sun, lots of spacing */}
          <div style={{display:"flex",flexDirection:"column",gap:20,alignItems:"center",paddingTop:8,minWidth:170}}>
            <TrashCan absentClips={absent} onDrop={onDrop} onDragStart={onDragStart}/>
            {/* Spacer */}
            <div style={{height:16}}/>
            <button onClick={()=>setShowEdit(true)}
              style={{background:"linear-gradient(135deg,#54A0FF,#2e86de)",color:"#fff",border:"none",
                borderRadius:13,padding:"12px 22px",fontFamily:"'Fredoka One',cursive",fontSize:14,
                cursor:"pointer",boxShadow:"0 4px 14px rgba(84,160,255,0.45)",transition:"transform .15s",whiteSpace:"nowrap"}}
              onMouseEnter={e=>e.currentTarget.style.transform="scale(1.07)"}
              onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}>
              ✏️ Editar Fichas
            </button>
            <button onClick={()=>{setClips(p=>p.map(c=>({...c,stage:1})));pop("🔄 ¡Todos a Bien!");}}
              style={{background:"linear-gradient(135deg,#1DD1A1,#0abf7a)",color:"#fff",border:"none",
                borderRadius:13,padding:"11px 20px",fontFamily:"'Fredoka One',cursive",fontSize:13,
                cursor:"pointer",boxShadow:"0 4px 12px rgba(29,209,161,0.35)",transition:"transform .15s",whiteSpace:"nowrap"}}
              onMouseEnter={e=>e.currentTarget.style.transform="scale(1.07)"}
              onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}>
              🔄 Reiniciar Todo
            </button>
            {/* Extra gap before timer */}
            <div style={{height:8}}/>
            <Timer/>
          </div>
        </div>
      </div>

      {showEdit&&<EditModal clips={clips} onSave={save} onClose={()=>setShowEdit(false)}/>}
    </>
  );
}
